export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(([x, y]) => keyOf(x, y)));

  const candidates = new Map<string, Cell>();
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const k = keyOf(nx, ny);
      candidates.set(k, [nx, ny]);
      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
    }
  }

  const result: Cell[] = [];
  for (const [k, cell] of candidates) {
    if (survives(alive.has(k), neighborCounts.get(k) ?? 0)) {
      result.push(cell);
    }
  }
  return result;
}

