function countNeighborsAround(cells: Cell[]): Map<string, { cell: Cell; count: number }> {
  const counts = new Map<string, { cell: Cell; count: number }>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const k = keyOf(nx, ny);
      const entry = counts.get(k);
      if (entry) {
        entry.count++;
      } else {
        counts.set(k, { cell: [nx, ny], count: 1 });
      }
    }
  }
  return counts;
}

export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(([x, y]) => keyOf(x, y)));
  const neighbors = countNeighborsAround(cells);

  const result: Cell[] = [];
  for (const [k, { cell, count }] of neighbors) {
    if (survives(alive.has(k), count)) {
      result.push(cell);
    }
  }
  return result;
}

