type NeighborEntry = { cell: Cell; count: number };

function neighborhoodOf(cells: Cell[]): Map<string, NeighborEntry> {
  const neighborhood = new Map<string, NeighborEntry>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const k = keyOf(nx, ny);
      const entry = neighborhood.get(k) ?? { cell: [nx, ny], count: 0 };
      entry.count++;
      neighborhood.set(k, entry);
    }
  }
  return neighborhood;
}

export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(([x, y]) => keyOf(x, y)));
  const neighborhood = neighborhoodOf(cells);

  const result: Cell[] = [];
  for (const [k, { cell, count }] of neighborhood) {
    if (survives(alive.has(k), count)) {
      result.push(cell);
    }
  }
  return result;
}
